func unsafeWrapVideoEncoder(base *gobject.ObjectInstance) *VideoEncoderInstance {
	return &VideoEncoderInstance{
		ElementInstance: gst.ElementInstance{
			ObjectInstance: gst.ObjectInstance{
				InitiallyUnownedInstance: gobject.InitiallyUnownedInstance{
					ObjectInstance: *base,
				},
			},
		},
		PresetInstance: gst.PresetInstance{
			Instance: *base,
		},
	}
}

func init() {
	gobject.RegisterObjectCasting(
		TypeVideoEncoder,
		func (inst *gobject.ObjectInstance) gobject.Object {
			return unsafeWrapVideoEncoder(inst)
		},
	)
}

func marshalVideoEncoderInstance(p unsafe.Pointer) (any, error) {
	return unsafeWrapVideoEncoder(gobject.ValueFromNative(p).Object()), nil
}

